class ProfileActivity : Activity() {
    companion object {
        const val EXTRA_USER_ID = "extra_user_id"
        const val EXTRA_TAB = "extra_tab"
        const val EXTRA_SOURCE = "extra_source"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val userId = intent.getStringExtra(EXTRA_USER_ID) ?: "unknown"
        val tab = intent.getStringExtra(EXTRA_TAB) ?: "default"
        val source = intent.getStringExtra(EXTRA_SOURCE)

        DeepLinkAnalytics.trackDeepLinkOpened(
            source = source,
            destination = "profile",
            extras = mapOf("userId" to userId, "tab" to tab)
        )

        val textView = TextView(this).apply {
            text = "Profile Activity\nUser ID: $userId\nTab: $tab\nSource: ${source ?: "direct"}"
            textSize = 20f
            setPadding(32, 32, 32, 32)
        }
        setContentView(textView)
    }
}

